SELECT leaf_1.playerid, leaf_1.year, leaf_1.ga, leaf_1.gp, leaf_1.conference, leaf_1.award FROM (SELECT g.playerid, g.year, g.ga, g.gp, a.fullname AS conference, ap.award FROM goalies g JOIN teams t ON g.tmid = t.tmid JOIN abbrev a ON t.confid = a.code JOIN awardsplayers ap ON g.playerid = ap.playerid WHERE (a.type = 'Conference') AND (a.fullname = 'Campbell Conference') AND (ap.award IS NOT NULL) GROUP BY g.playerid, g.year, g.ga, g.gp, a.fullname, ap.award) AS leaf_1
